import{c as e,S as a,j as i,m as s}from"./chunks/framework.DglpM5Ly.js";const m=JSON.parse('{"title":"Charniga et al. 2024 checklist","description":"","frontmatter":{},"headers":[],"relativePath":"charniga-checklist.md","filePath":"charniga-checklist.md","lastUpdated":null}'),r={name:"charniga-checklist.md"};function n(l,t,o,d,h,g){return a(),i("div",null,[...t[0]||(t[0]=[s('<h1 id="Charniga-et-al.-2024-checklist" tabindex="-1">Charniga <em>et al.</em> 2024 checklist <a class="header-anchor" href="#Charniga-et-al.-2024-checklist" aria-label="Permalink to &quot;Charniga _et al._ 2024 checklist {#Charniga-et-al.-2024-checklist}&quot;">​</a></h1><p><a href="https://doi.org/10.1371/journal.pcbi.1012520" target="_blank" rel="noreferrer">Charniga K, Park SW, Akhmetzhanov AR <em>et al.</em> &quot;Best practices for estimating and reporting epidemiological delay distributions of infectious diseases.&quot; <em>PLoS Comput Biol</em> 2024;20(10):e1012520.</a></p><p>The table below maps each Table 2 checklist item from Charniga <em>et al.</em> 2024 to where (and how) it is addressed in this analysis. ✅ = done, 🟡 = partial / done with documented caveats, ❌ = not done. We have tried to be honest about partial coverage rather than claim more than the deposit supports.</p><h2 id="Estimation" tabindex="-1">Estimation <a class="header-anchor" href="#Estimation" aria-label="Permalink to &quot;Estimation {#Estimation}&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:right;">#</th><th style="text-align:right;">Charniga 2024 item</th><th style="text-align:right;">Status</th><th style="text-align:right;">Where in this repo</th><th style="text-align:right;">Note</th></tr></thead><tbody><tr><td style="text-align:right;">1</td><td style="text-align:right;">Adjust for censoring (always), right truncation (when needed), and dynamical bias (when needed); state which adjustments were made</td><td style="text-align:right;">🟡</td><td style="text-align:right;"><a href="https://github.com/epiforecasts/bdbv-linelist-analysis/blob/main/src/model.jl" target="_blank" rel="noreferrer"><code>src/model.jl</code></a> and <a href="/bdbv-linelist-analysis/previews/PR54/model#Likelihood">Model</a></td><td style="text-align:right;">Double interval censoring at 1-day bins on both endpoints via <code>CensoredDistributions.double_interval_censored</code>. No right-truncation or dynamical-bias adjustment because the 2012 Isiro outbreak is fitted retrospectively in 2026 on the closed Rosello deposit — neither bias applies.</td></tr><tr><td style="text-align:right;">2</td><td style="text-align:right;">Fit more than one probability distribution and use model-selection criteria; visualise the fit</td><td style="text-align:right;">✅</td><td style="text-align:right;"><a href="/bdbv-linelist-analysis/previews/PR54/analysis#Family-comparison">Analysis walkthrough — Family comparison</a></td><td style="text-align:right;">LogNormal, Gamma, and Weibull all fitted; WAIC ranking + side-by-side posterior-predictive panels per family. Gamma wins.</td></tr><tr><td style="text-align:right;">3</td><td style="text-align:right;">Convert distribution parameters to summary statistics correctly</td><td style="text-align:right;">✅</td><td style="text-align:right;"><a href="/bdbv-linelist-analysis/previews/PR54/model#Common-parametrisation-across-families">Model — Common parametrisation</a></td><td style="text-align:right;">All families share a log-mean / log-shape parametrisation; conversion uses <code>Distributions.jl</code> built-ins (<code>Gamma(k, μ/k)</code>, <code>Weibull(α, μ/Γ(1+1/α))</code>, <code>LogNormal(log_median, log_sd)</code>). Documented in a single table.</td></tr><tr><td style="text-align:right;">4</td><td style="text-align:right;">Stratify or add subgroups when sample size allows and group differences are hypothesised</td><td style="text-align:right;">🟡</td><td style="text-align:right;"><a href="./api"><code>bdbv_model_stratified</code></a> and <a href="./model">Model</a></td><td style="text-align:right;">HCW stratification implemented for the delay block (<code>β_*_hcw</code> log-mean shifts on Gamma); HCW, case definition (Probable vs Confirmed), and standardised age in the CFR block. Sex is recorded but not stratified — <a href="/bdbv-linelist-analysis/previews/PR54/limitations#Model">Limitations</a> explains why (Kratz 2015&#39;s community-vs-ETC stratum is not reproducible from the Rosello deposit).</td></tr><tr><td style="text-align:right;">5</td><td style="text-align:right;">Check model diagnostics (R̂, divergent transitions, ESS)</td><td style="text-align:right;">✅</td><td style="text-align:right;"><a href="/bdbv-linelist-analysis/previews/PR54/analysis#Family-comparison">Analysis walkthrough — Family comparison</a></td><td style="text-align:right;">Per-family table reports max R̂, min bulk ESS, and divergent transition count. Across all three families: max R̂ ≤ 1.002, min ESS ≥ 3,200, 0 divergent transitions.</td></tr></tbody></table><h2 id="Reporting" tabindex="-1">Reporting <a class="header-anchor" href="#Reporting" aria-label="Permalink to &quot;Reporting {#Reporting}&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:right;">#</th><th style="text-align:right;">Charniga 2024 item</th><th style="text-align:right;">Status</th><th style="text-align:right;">Where in this repo</th><th style="text-align:right;">Note</th></tr></thead><tbody><tr><td style="text-align:right;">6</td><td style="text-align:right;">Report measures of central tendency and variability (mean <strong>and</strong> SD/variance/dispersion)</td><td style="text-align:right;">✅</td><td style="text-align:right;"><a href="/bdbv-linelist-analysis/previews/PR54/analysis#Headline-Gamma-estimates">Analysis walkthrough — Headline estimates</a> and <a href="/bdbv-linelist-analysis/previews/PR54/analysis#Derived-(convolved)-marginals">— Derived (convolved) marginals</a></td><td style="text-align:right;">Median, mean <strong>and SD</strong> reported for every atomic and convolved delay (the convolved-marginals table gained an <code>sd (95% CrI)</code> column once <code>_convolve_delays</code> started returning per-draw SDs). Per-draw shape/scale/SD also exposed in <code>posterior_&lt;family&gt;.csv</code>.</td></tr><tr><td style="text-align:right;">7</td><td style="text-align:right;">Report key quantiles (e.g. 2.5, 5, 25, 50, 75, 95, 97.5, 99) of the distribution</td><td style="text-align:right;">🟡</td><td style="text-align:right;"><a href="./analysis">Analysis walkthrough</a></td><td style="text-align:right;">The 50th percentile is reported as the median; the 95th percentile is reported for the convolved onset → death and onset → discharge marginals. A full quantile grid (5/25/75/95/99) is not produced — <code>output/</code> posteriors allow it to be computed downstream.</td></tr><tr><td style="text-align:right;">8</td><td style="text-align:right;">Report the fitted-distribution parameters</td><td style="text-align:right;">🟡</td><td style="text-align:right;"><a href="https://github.com/epiforecasts/bdbv-linelist-analysis/tree/main/output" target="_blank" rel="noreferrer"><code>output/</code></a> posterior CSV; parametrisation table in <a href="/bdbv-linelist-analysis/previews/PR54/model#Common-parametrisation-across-families">Model</a></td><td style="text-align:right;">The on-page tables emphasise summary statistics (median, mean, 95% CrI). Latent log-mean / log-shape draws are written to the <code>main-latest</code> rolling-release CSV bundle so the underlying Gamma <code>(shape, scale)</code>, LogNormal <code>(logmean, logsd)</code>, or Weibull <code>(shape, scale)</code> can be reconstructed exactly.</td></tr><tr><td style="text-align:right;">9</td><td style="text-align:right;">Report uncertainty (90% or 95% intervals) on every estimate</td><td style="text-align:right;">✅</td><td style="text-align:right;"><a href="./analysis">Analysis walkthrough</a> throughout</td><td style="text-align:right;">All headline numbers, derived marginals, CFR strata, and log-OR coefficients are reported as <code>median (2.5% – 97.5%)</code>.</td></tr><tr><td style="text-align:right;">10</td><td style="text-align:right;">Report study-sample characteristics (sample size, age, sex, location, route of exposure, vaccination status if any)</td><td style="text-align:right;">✅</td><td style="text-align:right;"><a href="/bdbv-linelist-analysis/previews/PR54/analysis#Outbreak-context">Analysis walkthrough — Outbreak context</a>; <a href="https://github.com/epiforecasts/bdbv-linelist-analysis#data-provenance" target="_blank" rel="noreferrer">README — Data provenance</a>; <a href="/bdbv-linelist-analysis/previews/PR54/limitations#Data">Limitations — Data</a></td><td style="text-align:right;">The walkthrough opens with an &quot;Outbreak context&quot; block tabulating n, onset window, age (median + IQR), sex split, HCW split, case-definition mix, and outcome counts directly from <code>data/linelist.csv</code>. Route of exposure is not recorded in the deposit; no vaccine was available in 2012 (vaccination status not applicable).</td></tr><tr><td style="text-align:right;">11</td><td style="text-align:right;">Report the epidemic curve and any control measures in place</td><td style="text-align:right;">🟡</td><td style="text-align:right;"><a href="/bdbv-linelist-analysis/previews/PR54/analysis#Epidemic-curve">Analysis walkthrough — Epidemic curve</a></td><td style="text-align:right;">Weekly onset epi curve with HCW subcounts is rendered live on the docs site. Control measures are mentioned narratively in <a href="/bdbv-linelist-analysis/previews/PR54/limitations#Generalisability">Limitations</a> (MSF ETC support; rural mining-influenced setting) rather than as a structured timeline.</td></tr><tr><td style="text-align:right;">12</td><td style="text-align:right;">Provide anonymised / de-identified line-list data and documented code</td><td style="text-align:right;">✅</td><td style="text-align:right;"><a href="https://github.com/epiforecasts/bdbv-linelist-analysis/blob/main/data/linelist.csv" target="_blank" rel="noreferrer"><code>data/linelist.csv</code></a>; <a href="https://github.com/epiforecasts/bdbv-linelist-analysis/tree/main/src" target="_blank" rel="noreferrer"><code>src/</code></a>; <a href="https://github.com/epiforecasts/bdbv-linelist-analysis/releases/tag/main-latest" target="_blank" rel="noreferrer"><code>output/</code> rolling release</a></td><td style="text-align:right;">The bundled CSV is Rosello <em>et al.</em> 2015&#39;s supplementary file 1 (CC-BY 4.0) subset to BDBV — already anonymised at source. All Julia code (model, post-processing, plotting) is MIT-licensed in this repo. The full executable walkthrough is published as the docs site, and posterior CSVs + figures ship as a <code>main-latest</code> GitHub release.</td></tr></tbody></table><h2 id="Items-13-Table-3-—-incubation-period-and-serial-interval" tabindex="-1">Items 13+ (Table 3 — incubation period &amp; serial interval) <a class="header-anchor" href="#Items-13-Table-3-—-incubation-period-and-serial-interval" aria-label="Permalink to &quot;Items 13+ (Table 3 — incubation period &amp; serial interval) {#Items-13-Table-3-—-incubation-period-and-serial-interval}&quot;">​</a></h2><p>Charniga <em>et al.</em> 2024 Table 3 adds recommendations specific to incubation-period and serial-interval estimation (exposure-window encoding, transmission-pair confidence, transmission-direction ordering, support for negative serial intervals).</p><p><strong>Not applicable here.</strong> The Rosello deposit has no exposure dates and no transmission pairs, so neither the incubation period nor the serial interval is estimated in this work. See <a href="/bdbv-linelist-analysis/previews/PR54/limitations#Data">Limitations — Data</a> for the rationale and the MacNeil 2010 / Zaire-EVD priors recommended for downstream nowcasting or R&lt;sub&gt;t&lt;/sub&gt; work that needs these distributions.</p><h2 id="How-to-update-this-page" tabindex="-1">How to update this page <a class="header-anchor" href="#How-to-update-this-page" aria-label="Permalink to &quot;How to update this page {#How-to-update-this-page}&quot;">​</a></h2><p>When the model or reporting changes, edit the table directly. Status should err on the side of 🟡 over ✅ whenever a documented caveat exists. The LLM-friendly column layout (Charniga item ↔ status ↔ location ↔ note) is deliberate — it lets future automated reviews re-verify each row by following the link in the third column.</p>',12)])])}const p=e(r,[["render",n]]);export{m as __pageData,p as default};
